import fs from 'node:fs/promises'
import path from 'node:path'
import { fileURLToPath } from 'node:url'
import { bundledLanguagesInfo } from 'shiki/langs'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const generatedDir = path.resolve(__dirname, '../src/generated')
const generatedFile = path.join(generatedDir, 'shiki-lang-loaders.ts')

const langIds = [...new Set(bundledLanguagesInfo.map(({ id }) => id))].sort()

const lines = [
  '// This file is auto-generated by scripts/generate-shiki-lang-loaders.mjs.',
  '// Do not edit manually.',
  '',
  'export const langLoaders = {',
  ...langIds.map(
    (id) =>
      `  ${JSON.stringify(id)}: () => require(${JSON.stringify(`@shikijs/langs/${id}`)}).default,`,
  ),
  '} as const',
  '',
]

await fs.mkdir(generatedDir, { recursive: true })
await fs.writeFile(generatedFile, lines.join('\n'))
